import{Q as s,bb as a,C as o,x as r,O as n,bl as i,M as l,h as c,at as d,N as p}from"./Cbe0nSeg.js";const m={class:"wrap measure stack-lg",style:{"padding-block":"clamp(3rem, 6vw, 5rem)"}},y=s({__name:"ops-platform",setup(u){return a({title:"Operations platform — STITCH AND ASH",description:"STITCH AND ASH operations platform recommendation."}),(f,e)=>{const t=c;return d(),o("main",m,[r("p",null,[n(t,{to:"/"},{default:i(()=>[...e[0]||(e[0]=[p("← STITCH AND ASH",-1)])]),_:1})]),e[1]||(e[1]=l('<div class="stack"><h1 style="font-family:var(--font-display);font-size:clamp(2rem, 4vw, 3rem);font-weight:500;">Operations platform recommendation</h1><p style="font-size:var(--text-lg);color:var(--bone);"> Do not build an admin sales/orders/shipping/inventory dashboard from scratch right now. Use Shopify as the system of record and keep this site as the branded front-end. </p></div><section class="stack"><h2 class="eyebrow">Why Shopify first</h2><ul class="stack" style="padding-inline-start:1.2rem;color:var(--ash-silver);"><li>Orders, payments, taxes, refunds, fraud checks, discounts, and customer accounts are already solved.</li><li>Inventory and SKU variants are mature enough for apparel sizes, colors, blanks, and limited drops.</li><li>Shipping labels, fulfillment status, notifications, and returns can be handled in one admin surface.</li><li>Buy Buttons or Storefront API can plug into Astro without replacing the visual site.</li><li>It gives human admins one operational console while Paperclip stays focused on software work.</li></ul></section><section class="stack"><h2 class="eyebrow">Recommended shape</h2><ol class="stack" style="padding-inline-start:1.2rem;color:var(--ash-silver);"><li>Set up Shopify for products, inventory, checkout, orders, shipping, tax, and customer support.</li><li>Embed Shopify Buy Buttons or use Hydrogen/Storefront API only where the brand experience needs it.</li><li>Send regular customer/site reports to a human admin queue.</li><li>Send admin-confirmed software bugs to Paperclip&#39;s software development team.</li><li>Add Paperclip automation later for triage, QA, and release notes — not order fulfillment state.</li></ol></section><section class="stack"><h2 class="eyebrow">Alternatives</h2><p style="color:var(--ash-silver);line-height:1.6;"> Medusa or Saleor are viable if we need full OSS ownership and custom fulfillment logic, but they add hosting, security, payment, tax, and admin-maintenance burden. WooCommerce is cheaper but more plugin-heavy. Square is fine for POS-first workflows. For this brand, Shopify is the lowest-risk e2e operational choice. </p></section>',4))])}}});export{y as default};
